  2→ * Todo list focus management and empty state -- progressive enhancement for HTMX.
  3→ *
  4→ * Focus management:
  5→ * After an HTMX delete swap removes a todo item from the DOM, focus
  6→ * would otherwise be lost (sent to <body>). This script moves focus
  7→ * to the logical next element:
  8→ *   1. Next sibling todo item (if one exists)
  9→ *   2. Previous sibling todo item (if deleted was last in list)
 10→ *   3. The "New todo" input (if the list is now empty)
 11→ *
 12→ * Inline edit focus:
 13→ * Entering edit mode focuses the edit input. Saving or canceling
 14→ * focuses the edit link on the restored item.
 15→ *
 16→ * Empty state transitions:
 17→ * When the last item is deleted, shows the "No todos yet." message
 18→ * and hides the empty list. When the first item is added to an empty
 19→ * list, hides the message and shows the list.
 20→ *
 21→ * A11y: Focus management after DOM removal is required by WCAG 2.4.3
 22→ * (Focus Order) and is part of our HTMX Focus Management Protocol.
 23→ */
 24→(function () {
 25→  "use strict";
 26→
 27→  // Track the focus target before the swap removes the element
 28→  var pendingFocusTarget = null;
 29→  var pendingDeleteSwap = false;
 30→
 31→  document.body.addEventListener("htmx:beforeSwap", function (e) {
 32→    var target = e.detail.target;
 33→
 34→    // Only handle swaps targeting todo items
 35→    if (!target || !target.classList || !target.classList.contains("todo-item")) {
 36→      return;
 37→    }
 38→
 39→    var responseText = e.detail.xhr ? e.detail.xhr.responseText : "";
 40→
 41→    // Empty response = delete operation
 42→    if (responseText.trim() === "") {
 43→      pendingDeleteSwap = true;
 44→
 45→      var nextItem = target.nextElementSibling;
 46→      var prevItem = target.previousElementSibling;
 47→
 48→      if (nextItem && nextItem.classList.contains("todo-item")) {
 49→        pendingFocusTarget = { type: "element", el: nextItem };
 50→      } else if (prevItem && prevItem.classList.contains("todo-item")) {
 51→        pendingFocusTarget = { type: "element", el: prevItem };
 52→      } else {
 53→        pendingFocusTarget = { type: "element", el: document.getElementById("title") };
 54→      }
 55→      return;
 56→    }
 57→
 58→    // Check if the response contains the edit form (entering edit mode)
 59→    if (responseText.indexOf("todo-item--editing") !== -1) {
 60→      pendingFocusTarget = { type: "selector", selector: "#" + target.id + " .todo-item__edit-input" };
 61→      return;
 62→    }
 63→
 64→    // Check if the response is a normal todo item (exiting edit mode)
 65→    if (responseText.indexOf("todo-item__edit") !== -1 && responseText.indexOf("todo-item--editing") === -1) {
