 59→fn build_action_view(action: &NextAction, contexts: &[Context]) -> NextActionView {
 60→    let context_name = contexts
 61→        .iter()
 62→        .find(|c| c.id() == action.context_id())
 63→        .map(|c| c.name().as_str().to_string())
 64→        .unwrap_or_else(|| "Unknown".to_string());
 65→
 66→    NextActionView {
 67→        id: action.id().as_uuid().to_string(),
 68→        title: action.title().as_str().to_string(),
 69→        context_name,
 70→    }
